mapper.select:
select L_ID, L_RULE_NO, C_CONTROL_TYPE, C_PORT_TYPE, VC_PORT_CODE, D_MODIFY_TIME, 
C_VALID_STATUS
from T_COMP_RULEPORTBINDING


            and C_PORT_TYPE = #{type}


             and VC_PORT_CODE = #{code}

select L_ASSET_ID ASSETID
from TRADE.TASSET


            and L_FUND_ID = #{fundid}

select   L_COMBI_ID COMBID
from TRADE.TCOMBI


            and L_FUND_ID = #{fundid}
